import{_ as t,o,c as a,ad as r}from"./chunks/framework.DdcUsuRQ.js";const u=JSON.parse('{"title":"Chroma range","description":"The OKLCH C-channel envelope the engine clamps each role into. Two numbers in 0..~0.5.","frontmatter":{"title":"Chroma range","description":"The OKLCH C-channel envelope the engine clamps each role into. Two numbers in 0..~0.5.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/role-schema/chroma-range"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/role-schema/chroma-range"}],["meta",{"property":"og:title","content":"Chroma range: iridis"}],["meta",{"property":"og:description","content":"The OKLCH C-channel envelope the engine clamps each role into. Two numbers in 0..~0.5."}],["meta",{"name":"twitter:title","content":"Chroma range: iridis"}],["meta",{"name":"twitter:description","content":"The OKLCH C-channel envelope the engine clamps each role into. Two numbers in 0..~0.5."}],["meta",{"name":"description","content":"The OKLCH C-channel envelope the engine clamps each role into. Two numbers in 0..~0.5."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Role Schema\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":4,\\"name\\":\\"Chroma range\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema/chroma-range\\"}]}"]]},"headers":[],"relativePath":"reference/role-schema/chroma-range.md","filePath":"reference/role-schema/chroma-range.md","lastUpdated":1779033869000}'),n={name:"reference/role-schema/chroma-range.md"};function i(c,e,s,d,h,l){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="chroma-range" tabindex="-1">Chroma range <a class="header-anchor" href="#chroma-range" aria-label="Permalink to &quot;Chroma range&quot;">​</a></h1><p>The <code>[min, max]</code> envelope on the OKLCH <strong>C</strong> channel that the engine clamps the resolved role into. Encodes how saturated a role is allowed to be: neutrals near <code>0</code>, accents near <code>0.25+</code>.</p><h2 id="shape" tabindex="-1">Shape <a class="header-anchor" href="#shape" aria-label="Permalink to &quot;Shape&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Range</th></tr></thead><tbody><tr><td><code>chromaRange[0]</code></td><td><code>number</code></td><td><code>[0, ~0.5]</code>, lower bound</td></tr><tr><td><code>chromaRange[1]</code></td><td><code>number</code></td><td><code>[0, ~0.5]</code>, upper bound, <code>&gt;= [0]</code></td></tr></tbody></table><p>The practical upper limit is <code>~0.4</code>; beyond that most hues fall outside the sRGB and Display-P3 gamuts and get mapped back during emit.</p><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>clamp:oklch</code> checks each role&#39;s C against <code>chromaRange</code>:</p><ul><li><code>C &lt; chromaRange[0]</code> → push to <code>chromaRange[0]</code>. Forces a minimum saturation; useful for accents that must not collapse to grey.</li><li><code>C &gt; chromaRange[1]</code> → pull to <code>chromaRange[1]</code>. Forces a maximum saturation; useful for surfaces and text roles that must stay near-neutral regardless of seed.</li></ul><h2 id="what-it-means" tabindex="-1">What it means <a class="header-anchor" href="#what-it-means" aria-label="Permalink to &quot;What it means&quot;">​</a></h2><p>Chroma encodes <strong>how chromatic</strong> a role is, independent of which hue. A <code>muted</code> text role with <code>chromaRange: [0, 0.04]</code> will stay near-grey even if the user supplies a violent magenta seed.</p><ul><li>Neutral roles (<code>background</code>, <code>text</code>, <code>divider</code>, <code>surface</code>): <code>[0, 0.06]</code>.</li><li>Muted roles (<code>muted</code>, <code>text-subtle</code>, <code>border</code>): <code>[0, 0.08]</code>.</li><li>Accent roles (<code>brand</code>, <code>link</code>, <code>success</code>, <code>error</code>): <code>[0.10, 0.32]</code>.</li><li>Highly chromatic roles (syntax tokens, signal colours): <code>[0.14, 0.32]</code>.</li></ul><h2 id="how-to-author" tabindex="-1">How to author <a class="header-anchor" href="#how-to-author" aria-label="Permalink to &quot;How to author&quot;">​</a></h2><ul><li>Pair every chroma range with a sensible lightness range. A high chroma at low lightness produces deep saturated colours; high chroma at high lightness produces pastels.</li><li>Keep the <strong>upper bound</strong> at or below <code>0.32</code> for sRGB-only emit targets. Anything higher falls outside sRGB for most hues and gets gamut-mapped to a duller value.</li><li>Use the <strong>same</strong> chroma range in dark and light framing variants unless you specifically want one mode to read as more saturated than the other.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./lightness-range">Lightness range</a>: the orthogonal envelope on the L channel.</li><li><a href="./../oklch">OKLCH reference</a>: full conversion math + chroma boundaries.</li><li><a href="./../../concepts/role-schemas">Role schemas overview</a>.</li></ul>',15)])])}const p=t(n,[["render",i]]);export{u as __pageData,p as default};
